// scoring.js — Pure ten-pin bowling scoring logic.
// No DOM, no rendering. Deterministic and unit-testable.
//
// Data model:
//   A game is an array of up to 10 frames.
//   Each frame: { rolls: number[], score: number|null, cumulative: number|null }
//   `rolls` holds pins knocked down per ball in that frame (0..10).
//   Frames 1-9 have 1 or 2 rolls (1 if a strike). Frame 10 has 2 or 3 rolls.
//
// This module is intentionally framework-free so its correctness can be read
// straight off the page and checked with a tiny harness (see scoring.test.js).

export const TOTAL_FRAMES = 10;
export const PINS = 10;

export function createGame() {
  const frames = [];
  for (let i = 0; i < TOTAL_FRAMES; i++) {
    frames.push({ rolls: [], score: null, cumulative: null });
  }
  return {
    frames,
    currentFrame: 0, // 0-indexed frame in progress
    currentRoll: 0, // roll index within the current frame
    complete: false,
  };
}

// Is the given (0-indexed) frame a strike? (first ball knocks all 10)
function isStrike(frame) {
  return frame.rolls.length >= 1 && frame.rolls[0] === PINS;
}

// Is the given frame a spare? (two balls sum to 10, first wasn't a strike)
function isSpare(frame) {
  return (
    frame.rolls.length >= 2 &&
    frame.rolls[0] !== PINS &&
    frame.rolls[0] + frame.rolls[1] === PINS
  );
}

// How many pins are still standing for the *current* ball in a frame.
// Used to validate input and to know how many pins to render.
export function pinsStandingForCurrentBall(game) {
  const f = game.frames[game.currentFrame];
  if (!f) return 0;
  const isLast = game.currentFrame === TOTAL_FRAMES - 1;

  if (!isLast) {
    // Frames 1-9: if first ball was a strike the frame is over (handled by advance).
    if (game.currentRoll === 0) return PINS;
    return PINS - f.rolls[0];
  }

  // 10th frame: pins reset after a strike or spare clears the rack.
  const r = f.rolls;
  if (game.currentRoll === 0) return PINS;
  if (game.currentRoll === 1) {
    if (r[0] === PINS) return PINS; // fresh rack after a strike
    return PINS - r[0];
  }
  // third ball
  if (r[0] === PINS && r[1] === PINS) return PINS; // two strikes -> fresh rack
  if (r[0] === PINS) return PINS - r[1]; // strike then partial -> remainder of 2nd rack
  // first two were a spare -> fresh rack for bonus ball
  return PINS;
}

// Record a roll. `pins` = pins knocked down on this ball.
// Returns an object describing what happened so the UI can react:
//   { frameComplete, gameComplete, wasStrike, wasSpare, rackReset }
export function roll(game, pins) {
  if (game.complete) return { frameComplete: false, gameComplete: true };

  const fi = game.currentFrame;
  const f = game.frames[fi];
  const isLast = fi === TOTAL_FRAMES - 1;
  pins = Math.max(0, Math.min(PINS, Math.round(pins)));

  f.rolls.push(pins);

  let frameComplete = false;
  let rackReset = false;
  const wasStrike = pins === PINS && game.currentRoll === 0;

  if (!isLast) {
    // Frames 1-9
    if (pins === PINS && game.currentRoll === 0) {
      // strike -> frame over
      frameComplete = true;
    } else if (game.currentRoll === 1) {
      frameComplete = true;
    } else {
      game.currentRoll = 1;
    }

    if (frameComplete) {
      game.currentFrame += 1;
      game.currentRoll = 0;
    }
  } else {
    // 10th frame logic
    const r = f.rolls;
    if (game.currentRoll === 0) {
      game.currentRoll = 1;
      if (pins === PINS) rackReset = true; // strike clears rack for ball 2
    } else if (game.currentRoll === 1) {
      // Decide whether a third ball is earned.
      const earnedThird = r[0] === PINS || r[0] + r[1] === PINS;
      if (earnedThird) {
        game.currentRoll = 2;
        // rack resets if strike on ball1, or spare just completed, or strike on ball2
        rackReset = r[0] === PINS ? r[1] === PINS : true;
      } else {
        frameComplete = true;
      }
    } else {
      // third ball always ends the game
      frameComplete = true;
    }

    if (frameComplete) {
      game.complete = true;
    }
  }

  recompute(game);

  const wasSpare =
    !wasStrike && f.rolls.length >= 2 && isSpare(f) && game.currentRoll <= 1;

  return {
    frameComplete,
    gameComplete: game.complete,
    wasStrike,
    wasSpare,
    rackReset,
  };
}

// Flatten all rolls across frames into a single sequence so strike/spare
// bonuses can look "ahead" to subsequent balls regardless of frame boundaries.
function flatRolls(frames) {
  const flat = [];
  // Map: frameIndex -> starting position in flat array
  const frameStart = [];
  for (let i = 0; i < frames.length; i++) {
    frameStart[i] = flat.length;
    for (const r of frames[i].rolls) flat.push(r);
  }
  return { flat, frameStart };
}

// Recompute per-frame scores + running totals for everything scorable so far.
export function recompute(game) {
  const frames = game.frames;
  const { flat, frameStart } = flatRolls(frames);
  let running = 0;

  for (let i = 0; i < TOTAL_FRAMES; i++) {
    const f = frames[i];
    if (f.rolls.length === 0) {
      f.score = null;
      f.cumulative = null;
      continue;
    }

    const isLast = i === TOTAL_FRAMES - 1;
    let frameScore = null;

    if (isLast) {
      // 10th frame: only scorable once its rolls are settled.
      const need = tenthFrameRollsNeeded(f);
      if (f.rolls.length >= need) {
        frameScore = f.rolls.reduce((a, b) => a + b, 0);
      }
    } else if (isStrike(f)) {
      // Need next two balls.
      const start = frameStart[i];
      const b1 = flat[start + 1];
      const b2 = flat[start + 2];
      if (b1 !== undefined && b2 !== undefined) {
        frameScore = PINS + b1 + b2;
      }
    } else if (isSpare(f)) {
      // Need next one ball.
      const start = frameStart[i];
      const b1 = flat[start + 2];
      if (b1 !== undefined) {
        frameScore = PINS + b1;
      }
    } else if (f.rolls.length >= 2) {
      frameScore = f.rolls[0] + f.rolls[1];
    }

    f.score = frameScore;
    if (frameScore === null) {
      f.cumulative = null;
    } else {
      running += frameScore;
      f.cumulative = running;
    }
  }
}

// How many rolls the 10th frame ultimately needs.
function tenthFrameRollsNeeded(f) {
  if (f.rolls.length === 0) return 2;
  if (f.rolls[0] === PINS) return 3; // strike -> 3 balls
  if (f.rolls.length >= 2 && f.rolls[0] + f.rolls[1] === PINS) return 3; // spare -> 3
  return 2;
}

// Best-known total so far (last cumulative that's been computed).
export function totalScore(game) {
  let total = 0;
  for (const f of game.frames) {
    if (f.cumulative !== null) total = f.cumulative;
  }
  return total;
}

// scoring.test.js — tiny harness, run with: node scoring.test.js
// Verifies the pure scoring module against canonical ten-pin scores.
import { createGame, roll, totalScore } from "./scoring.js";

function play(rolls) {
  const g = createGame();
  for (const p of rolls) {
    if (g.complete) break;
    roll(g, p);
  }
  return g;
}

let pass = 0;
let fail = 0;
function expect(name, got, want) {
  if (got === want) {
    pass++;
    console.log(`  ok   ${name}: ${got}`);
  } else {
    fail++;
    console.log(`  FAIL ${name}: got ${got}, want ${want}`);
  }
}

// 1. Perfect game: 12 strikes -> 300
expect("perfect game", totalScore(play(Array(12).fill(10))), 300);

// 2. All gutters -> 0
expect("all gutters", totalScore(play(Array(20).fill(0))), 0);

// 3. All spares of 5 (5,5 x10 + bonus 5) -> 150
{
  const rolls = [];
  for (let i = 0; i < 10; i++) rolls.push(5, 5);
  rolls.push(5); // 10th-frame bonus ball
  expect("all 5/5 spares", totalScore(play(rolls)), 150);
}

// 4. All nines, no spares (9 then miss, x10) -> 90
{
  const rolls = [];
  for (let i = 0; i < 10; i++) rolls.push(9, 0);
  expect("all nine-miss", totalScore(play(rolls)), 90);
}

// 5. Worked example from Wikipedia-style table:
//    Frame: X 7/ 9- X -8 8/ -6 X X X8(spare->no) ... use a known one.
//    Use: 1,4, 4,5, 6,/(spare 6,4), 5,/(5,5), X, 0,1, 7,/(7,3), 6,/(6,4), X, 2,/(2,8 spare)... too fiddly.
//    Instead a clean documented example: rolls below total to 133.
//    10,7,3,9,0,10,0,8,8,2,0,6,10,10,10,8,1  (from a common scoring tutorial = 167)
{
  // Strike, 7/ , 9- , Strike, -8, 8/, -6, Strike, Strike, Strike 8 1  -> 167
  const rolls = [10, 7, 3, 9, 0, 10, 0, 8, 8, 2, 0, 6, 10, 10, 10, 8, 1];
  expect("tutorial game", totalScore(play(rolls)), 167);
}

// 6. Spare in 10th frame grants exactly one bonus ball.
{
  const rolls = [];
  for (let i = 0; i < 9; i++) rolls.push(0, 0); // 9 empty frames
  rolls.push(5, 5, 7); // 10th: spare + 7 bonus = 17
  expect("10th-frame spare bonus", totalScore(play(rolls)), 17);
}

// 7. Strike in 10th frame grants exactly two bonus balls.
{
  const rolls = [];
  for (let i = 0; i < 9; i++) rolls.push(0, 0);
  rolls.push(10, 10, 10); // 10th: three strikes = 30
  expect("10th-frame strike bonus", totalScore(play(rolls)), 30);
}

console.log(`\n${pass} passed, ${fail} failed`);
if (fail > 0) process.exit(1);

// physics.js — Lightweight, self-contained bowling physics.
//
// Why custom physics instead of a CDN engine (cannon-es / rapier)?
//   - Zero extra network dependencies / WASM loads -> nothing else to break.
//   - A bowling lane is a constrained, mostly-2D problem (ball rolls in the
//     X/Z plane; pins topple). We don't need a general 3D solver.
//   - The simulation is deterministic given the same inputs, which keeps the
//     game predictable and debuggable.
//
// Coordinate system (world units = meters, roughly true to a real lane):
//   +Z runs from the foul line (z = 0) toward the pins (z = LANE_LENGTH).
//   X is left/right across the lane, centered at 0.
//   Y is up. Everything rolls on the y = 0 plane.
//
// A regulation lane is ~18.3 m foul-line-to-headpin and ~1.05 m wide; the ball
// is ~0.108 m radius and pins ~0.12 m wide. We scale loosely for feel.

export const LANE = {
  length: 18.3, // foul line to pin deck (m)
  width: 1.05, // playing surface width (m)
  halfWidth: 1.05 / 2,
  gutterDepth: 0.06,
  pinDeckZ: 18.0, // z of the head pin
};

export const BALL_RADIUS = 0.108;
export const PIN_RADIUS = 0.06; // collision radius (pin base)
export const PIN_HEIGHT = 0.38;
export const PIN_MASS = 1.5;
export const BALL_MASS = 6.0;

// Standard 10-pin triangle. Pin spacing center-to-center is ~0.305 m.
// Pin 1 (head) nearest the bowler; rows recede in +Z.
const PIN_SPACING = 0.305;
const ROW_DEPTH = (PIN_SPACING * Math.sqrt(3)) / 2;

export function pinLayout() {
  const z0 = LANE.pinDeckZ;
  const positions = [];
  // Row 0: 1 pin; Row 1: 2; Row 2: 3; Row 3: 4
  for (let row = 0; row < 4; row++) {
    const count = row + 1;
    const z = z0 + row * ROW_DEPTH;
    const xStart = -(count - 1) * 0.5 * PIN_SPACING;
    for (let i = 0; i < count; i++) {
      positions.push({ x: xStart + i * PIN_SPACING, z });
    }
  }
  // Reorder to standard pin numbering (1..10) for scoring/visuals.
  // Layout index order above is row-major; standard numbering:
  //   row0: 1 | row1: 2,3 | row2: 4,5,6 | row3: 7,8,9,10
  return positions.map((p, i) => ({ id: i + 1, x: p.x, z: p.z }));
}

export function createPins() {
  return pinLayout().map((p) => ({
    id: p.id,
    homeX: p.x,
    homeZ: p.z,
    x: p.x,
    z: p.z,
    y: 0,
    vx: 0,
    vz: 0,
    // tilt: how far the pin has tipped (radians). >~1.0 == fallen.
    tilt: 0,
    tiltAxisX: 0, // direction the pin falls toward
    tiltAxisZ: 0,
    angVel: 0,
    fallen: false,
    settled: false,
  }));
}

// Create a ball state. dir is a normalized {x,z}; speed in m/s; spin curves it.
export function createBall({ x, speed, dirX, dirZ, spin }) {
  return {
    x,
    y: 0,
    z: 0,
    vx: dirX * speed,
    vz: dirZ * speed,
    spin: spin || 0, // lateral acceleration coefficient (+ curves right)
    radius: BALL_RADIUS,
    rolling: true,
    inGutter: false,
    distance: 0,
  };
}

const GRAVITY = 9.81;
const ROLL_FRICTION = 0.045; // gentle deceleration while rolling
const HOOK_STRENGTH = 2.6; // how strongly spin curves the ball
const FALL_RATE = 7.0; // how fast a struck pin topples

// Step the whole simulation forward by dt seconds.
// Returns true while anything is still meaningfully moving.
export function step(state, dt) {
  const { ball, pins } = state;
  let active = false;

  // --- Ball integration ---
  if (ball.rolling) {
    active = true;

    // Spin (hook): lateral acceleration that fades as the ball slows, like
    // a real ball gripping the lane near the pins. Stronger at lower speed.
    const speed = Math.hypot(ball.vx, ball.vz);
    if (speed > 0.01) {
      const hook = ball.spin * HOOK_STRENGTH * (1 - Math.min(speed / 9, 1));
      // Perpendicular to travel direction.
      const px = ball.vz / speed;
      const pz = -ball.vx / speed;
      ball.vx += px * hook * dt;
      ball.vz += pz * hook * dt;
    }

    // Rolling friction.
    const decel = Math.exp(-ROLL_FRICTION * dt);
    ball.vx *= decel;
    ball.vz *= decel;

    ball.x += ball.vx * dt;
    ball.z += ball.vz * dt;
    ball.distance += speed * dt;

    // Gutter check: ball off the playing surface drops into a gutter and
    // can no longer hit pins.
    if (Math.abs(ball.x) > LANE.halfWidth - ball.radius * 0.5) {
      ball.inGutter = true;
      ball.x = Math.sign(ball.x) * (LANE.halfWidth + 0.04);
      ball.y = -LANE.gutterDepth;
      ball.vx = 0; // run straight down the gutter
    }

    // Ball reached the pit / went far enough -> stop.
    if (ball.z > LANE.pinDeckZ + 1.4 || speed < 0.25) {
      ball.rolling = false;
    }

    // --- Ball vs pins collision (only if on the lane) ---
    if (!ball.inGutter) {
      for (const pin of pins) {
        if (pin.fallen) continue;
        const dx = pin.x - ball.x;
        const dz = pin.z - ball.z;
        const dist = Math.hypot(dx, dz);
        const minDist = ball.radius + PIN_RADIUS;
        if (dist < minDist && dist > 1e-5) {
          // Transfer momentum to the pin along the contact normal.
          const nx = dx / dist;
          const nz = dz / dist;
          const impactSpeed = ball.vx * nx + ball.vz * nz;
          if (impactSpeed > 0) {
            const transfer = (impactSpeed * BALL_MASS) / (BALL_MASS + PIN_MASS);
            pin.vx += nx * transfer * 2.0;
            pin.vz += nz * transfer * 2.0;
            knock(pin, nx, nz, impactSpeed);
            // Ball loses a little speed and deflects slightly.
            ball.vx -= nx * transfer * (PIN_MASS / BALL_MASS) * 0.6;
            ball.vz -= nz * transfer * (PIN_MASS / BALL_MASS) * 0.6;
          }
        }
      }
    }
  }

  // --- Pin integration + pin-vs-pin collisions ---
  for (const pin of pins) {
    if (pin.settled) continue;
    const moving = Math.abs(pin.vx) > 0.02 || Math.abs(pin.vz) > 0.02;
    const toppling = pin.fallen && pin.tilt < Math.PI / 2;
    if (moving || toppling) active = true;

    if (pin.fallen) {
      // Advance the topple animation.
      if (pin.tilt < Math.PI / 2) {
        pin.tilt = Math.min(Math.PI / 2, pin.tilt + pin.angVel * dt);
      }
    }

    // Move pins that have lateral velocity (sliding/scattering).
    if (moving) {
      const pinDecel = Math.exp(-2.4 * dt);
      pin.vx *= pinDecel;
      pin.vz *= pinDecel;
      pin.x += pin.vx * dt;
      pin.z += pin.vz * dt;
    } else if (pin.fallen && pin.tilt >= Math.PI / 2 - 1e-3) {
      pin.settled = true;
    } else if (!pin.fallen) {
      // a standing pin with no velocity is settled
      pin.settled = !ball.rolling ? true : pin.settled;
    }
  }

  // Pin vs pin: a moving/falling pin knocks neighbors (chain reaction).
  for (let i = 0; i < pins.length; i++) {
    const a = pins[i];
    const aActive = Math.abs(a.vx) > 0.05 || Math.abs(a.vz) > 0.05;
    if (!aActive) continue;
    for (let j = 0; j < pins.length; j++) {
      if (i === j) continue;
      const b = pins[j];
      if (b.fallen) continue;
      const dx = b.x - a.x;
      const dz = b.z - a.z;
      const dist = Math.hypot(dx, dz);
      const minDist = PIN_RADIUS * 2 + 0.02;
      if (dist < minDist && dist > 1e-5) {
        const nx = dx / dist;
        const nz = dz / dist;
        const along = a.vx * nx + a.vz * nz;
        if (along > 0) {
          const transfer = along * 0.6;
          b.vx += nx * transfer;
          b.vz += nz * transfer;
          a.vx -= nx * transfer * 0.5;
          a.vz -= nz * transfer * 0.5;
          knock(b, nx, nz, along);
        }
      }
    }
  }

  return active;
}

// Mark a pin as knocked over, falling in the direction of impact.
function knock(pin, nx, nz, force) {
  if (pin.fallen) return;
  pin.fallen = true;
  pin.tiltAxisX = nx;
  pin.tiltAxisZ = nz;
  pin.angVel = FALL_RATE * Math.min(1.5, 0.6 + force * 0.15);
}

// Count pins knocked down (fallen far enough to no longer count as standing).
export function countFallen(pins) {
  return pins.filter((p) => p.fallen || p.tilt > 0.7).length;
}

// Has the simulation come to rest?
export function isSettled(state) {
  if (state.ball.rolling) return false;
  return state.pins.every(
    (p) => p.settled || (!p.fallen && Math.abs(p.vx) < 0.05 && Math.abs(p.vz) < 0.05),
  );
}

