input.content:
// scene.js — Three.js scene construction and visual sync.
// Builds the bowling alley (lane, gutters, pin deck, ball, pins, lighting)
// and exposes helpers to sync mesh transforms from the physics state.

import * as THREE from "three";
import { LANE, BALL_RADIUS, PIN_HEIGHT } from "./physics.js";

export function createRenderer(canvas) {
  const renderer = new THREE.WebGLRenderer({
    canvas,
    antialias: true,
    alpha: false,
  });
  renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
  renderer.shadowMap.enabled = true;
  renderer.shadowMap.type = THREE.PCFSoftShadowMap;
  renderer.outputColorSpace = THREE.SRGBColorSpace;
  renderer.toneMapping = THREE.ACESFilmicToneMapping;
  renderer.toneMappingExposure = 1.05;
  return renderer;
}

export function createCamera() {
  const cam = new THREE.PerspectiveCamera(
    50,
    window.innerWidth / window.innerHeight,
    0.1,
    100,
  );
  // Behind the foul line, slightly elevated, looking down the lane.
  cam.position.set(0, 1.5, -2.6);
  cam.lookAt(0, 0.4, 8);
  return cam;
}

// Procedural wood texture for the lane (canvas-based, no asset loading).
function woodTexture() {
  const c = document.createElement("canvas");
  c.width = 128;
  c.height = 1024;
  const ctx = c.getContext("2d");
  const grad = ctx.createLinearGradient(0, 0, c.width, 0);
  grad.addColorStop(0, "#c8923f");
  grad.addColorStop(0.5, "#e0ab57");
  grad.addColorStop(1, "#c8923f");
  ctx.fillStyle = grad;
  ctx.fillRect(0, 0, c.width, c.height);
  // Plank seams running lengthwise.
  ctx.strokeStyle = "rgba(90,55,20,0.35)";
  ctx.lineWidth = 1;
  const planks = 8;
  for (let i = 1; i < planks; i++) {
    const x = (c.width / planks) * i;
    ctx.beginPath();
    ctx.moveTo(x, 0);
    ctx.lineTo(x, c.height);
    ctx.stroke();
  }
  // Subtle grain noise.
  ctx.globalAlpha = 0.06;
  for (let i = 0; i < 2400; i++) {
    ctx.fillStyle = Math.random() > 0.5 ? "#7a4d18" : "#fff2cf";
    ctx.fillRect(Math.random() * c.width, Math.random() * c.height, 1, 2);
  }
  ctx.globalAlpha = 1;
  const tex = new THREE.CanvasTexture(c);
  tex.colorSpace = THREE.SRGBColorSpace;
  tex.wrapS = THREE.RepeatWrapping;
  tex.wrapT = THREE.RepeatWrapping;
  return tex;
}

export function buildAlley(scene) {
  // Ambient + directional lighting for soft shadows.
  scene.add(new THREE.AmbientLight(0x5566aa, 0.6));
  const key = new THREE.DirectionalLight(0xfff4e0, 1.15);
  key.position.set(-3, 8, 4);
  key.castShadow = true;
  key.shadow.mapSize.set(2048, 2048);
  key.shadow.camera.near = 1;
  key.shadow.camera.far = 40;
  key.shadow.camera.left = -3;
  key.shadow.camera.right = 3;
  key.shadow.camera.top = 22;
  key.shadow.camera.bottom = -3;
  key.shadow.bias = -0.0004;
  scene.add(key);

  const fill = new THREE.PointLight(0x88aaff, 0.5, 30);
  fill.position.set(0, 5, 16);
  scene.add(fill);

  // Background / room.
  scene.background = new THREE.Color(0x0a0d1a);
  scene.fog = new THREE.Fog(0x0a0d1a, 18, 34);

  // --- Lane surface ---
  const laneLen = LANE.length + 2;
  const laneGeo = new THREE.BoxGeometry(LANE.width, 0.1, laneLen);
  const tex = woodTexture();
  tex.repeat.set(1, 14);
  const laneMat = new THREE.MeshStandardMaterial({
    map: tex,
    roughness: 0.25,
    metalness: 0.0,
  });
  const lane = new THREE.Mesh(laneGeo, laneMat);
  lane.position.set(0, -0.05, laneLen / 2 - 1);
  lane.receiveShadow = true;
  scene.add(lane);

  // Glossy clear-coat sheen overlay (a faint reflective plane).
  const sheenMat = new THREE.MeshStandardMaterial({
    color: 0xffffff,
    transparent: true,
    opacity: 0.06,
    roughness: 0.05,
    metalness: 0.6,
  });
  const sheen = new THREE.Mesh(
    new THREE.PlaneGeometry(LANE.width, laneLen),
    sheenMat,
  );
  sheen.rotation.x = -Math.PI / 2;
  sheen.position.set(0, 0.001, laneLen / 2 - 1);
  scene.add(sheen);

  // --- Gutters ---
  const gutterMat = new THREE.MeshStandardMaterial({
    color: 0x1b2233,
    roughness: 0.4,
    metalness: 0.3,
  });
  for (const side of [-1, 1]) {
    const g = new THREE.Mesh(
      new THREE.BoxGeometry(0.14, 0.12, laneLen),
      gutterMat,
    );
    g.position.set(side * (LANE.halfWidth + 0.07), -0.11, laneLen / 2 - 1);
    g.receiveShadow = true;
    scene.add(g);
  }

  // Lane side rails / walls.
  const wallMat = new THREE.MeshStandardMaterial({
    color: 0x141a2e,
    roughness: 0.6,
  });
  for (const side of [-1, 1]) {
    const w = new THREE.Mesh(new THREE.BoxGeometry(0.1, 1.4, laneLen), wallMat);
    w.position.set(side * (LANE.halfWidth + 0.22), 0.6, laneLen / 2 - 1);
    scene.add(w);
  }

  // --- Aiming guide arrows on the lane (like real lane dots/arrows) ---
  const arrowMat = new THREE.MeshBasicMaterial({ color: 0x3a2a10 });
  for (let i = -3; i <= 3; i++) {
    if (i === 0) continue;
    const tri = new THREE.Mesh(new THREE.CircleGeometry(0.025, 8), arrowMat);
    tri.rotation.x = -Math.PI / 2;
    tri.position.set(i * 0.13, 0.002, 4.5 + Math.abs(i) * 0.35);
    scene.add(tri);
  }
  // Foul-line dots.
  for (let i = -4; i <= 4; i++) {
    const dot = new THREE.Mesh(new THREE.CircleGeometry(0.018, 8), arrowMat);
    dot.rotation.x = -Math.PI / 2;
    dot.position.set(i * 0.1, 0.002, 1.2);
    scene.add(dot);
  }

  // --- Pin deck backdrop / pit ---
  const backMat = new THREE.MeshStandardMaterial({
    color: 0x111827,
    roughness: 0.8,
  });
  const back = new THREE.Mesh(
    new THREE.BoxGeometry(LANE.width + 0.5, 2.4, 0.2),
    backMat,
  );
  back.position.set(0, 1.0, LANE.pinDeckZ + 1.6);
  scene.add(back);

  // Decorative neon strip behind pins.
  const neon = new THREE.Mesh(
    new THREE.BoxGeometry(LANE.width + 0.4, 0.06, 0.06),
    new THREE.MeshBasicMaterial({ color: 0x35e0ff }),
  );
  neon.position.set(0, 2.0, LANE.pinDeckZ + 1.5);
  scene.add(neon);

  return { lane };
}

// Build a single bowling pin mesh (lathe profile -> classic pin silhouette).
function makePinMesh(color) {
  const points = [];
  // Profile from base (y=0) to top, radii roughly to scale.
  const profile = [
    [0.0, 0.0],
    [0.045, 0.0],
    [0.06, 0.05],
    [0.058, 0.12],
    [0.035, 0.2],
    [0.028, 0.26],
    [0.04, 0.32],
    [0.03, 0.37],
    [0.0, 0.38],
  ];
  for (const [r, y] of profile) points.push(new THREE.Vector2(r, y));
  const geo = new THREE.LatheGeometry(points, 20);
  const mat = new THREE.MeshStandardMaterial({
    color: 0xfafafa,
    roughness: 0.35,
    metalness: 0.05,
  });
  const pin = new THREE.Mesh(geo, mat);
  pin.castShadow = true;
  pin.receiveShadow = true;

  // Red neck stripes.
  const stripeMat = new THREE.MeshStandardMaterial({
    color: 0xd11f2d,
    roughness: 0.4,
  });
  const s1 = new THREE.Mesh(
    new THREE.CylinderGeometry(0.031, 0.031, 0.02, 16, 1, true),
    stripeMat,
  );
  s1.position.y = 0.29;
  pin.add(s1);
  const s2 = new THREE.Mesh(
    new THREE.CylinderGeometry(0.033, 0.033, 0.02, 16, 1, true),
    stripeMat,
  );
  s2.position.y = 0.24;
  pin.add(s2);

  // Group so we can tilt the whole pin about its base.
  const group = new THREE.Group();
  group.add(pin);
  return group;
}

export function buildPins(scene, pinStates) {
  const meshes = [];
  for (const p of pinStates) {
    const m = makePinMesh();
    m.position.set(p.x, 0, p.z);
    scene.add(m);
    meshes.push(m);
  }
  return meshes;
}

export function buildBall(scene, color = 0x1565ff) {
  const geo = new THREE.SphereGeometry(BALL_RADIUS, 32, 32);
  const mat = new THREE.MeshStandardMaterial({
    color,
    roughness: 0.12,
    metalness: 0.35,
    emissive: new THREE.Color(color).multiplyScalar(0.05),
  });
  const ball = new THREE.Mesh(geo, mat);
  ball.castShadow = true;

  // Finger holes (three small dark dimples).
  const holeMat = new THREE.MeshStandardMaterial({ color: 0x05070d });
  for (const [a, b] of [
    [0.2, 0.1],
    [-0.1, 0.25],
    [0.1, 0.3],
  ]) {
    const hole = new THREE.Mesh(
      new THREE.SphereGeometry(BALL_RADIUS * 0.22, 12, 12),
      holeMat,
    );
    hole.position.set(
      Math.sin(a) * BALL_RADIUS,
      BALL_RADIUS * 0.8,
      Math.cos(b) * BALL_RADIUS * 0.6,
    );
    ball.add(hole);
  }
  scene.add(ball);
  return ball;
}

// Sync a ball mesh to its physics state; roll it visually.
export function syncBall(mesh, ball, dt) {
  mesh.position.set(ball.x, ball.y + BALL_RADIUS, ball.z);
  // Rolling rotation proportional to travel.
  const speed = Math.hypot(ball.vx, ball.vz);
  if (speed > 0.01) {
    const axisX = -ball.vz;
    const axisZ = ball.vx;
    const len = Math.hypot(axisX, axisZ) || 1;
    mesh.rotateOnWorldAxis(
      new THREE.Vector3(axisX / len, 0, axisZ / len),
      (speed * dt) / BALL_RADIUS,
    );
  }
}

// Sync pin meshes to physics states (position + topple tilt).
export function syncPins(meshes, pinStates) {
  for (let i = 0; i < meshes.length; i++) {
    const m = meshes[i];
    const p = pinStates[i];
    m.position.set(p.x, 0, p.z);
    if (p.fallen && p.tilt > 0) {
      // Rotate the group about its base toward the fall direction.
      const axis = new THREE.Vector3(p.tiltAxisZ, 0, -p.tiltAxisX).normalize();
      m.quaternion.setFromAxisAngle(axis, p.tilt);
      // When fully fallen, drop it to lie on the deck.
      m.position.y = 0;
    } else {
      m.quaternion.identity();
    }
    m.visible = true;
  }
}

// input.js — Mouse-driven aiming and throwing.
//
// Control scheme (easy with a mouse):
//   • Move the mouse left/right anywhere over the lane to set the ball's
//     starting position + aim. A dashed guide line previews the path.
//   • Press and HOLD to charge power; a power meter fills and pulses.
//   • Release to throw. Longer hold = more power (up to max).
//   • The SPIN slider (or A/D keys) sets hook; the guide line curves to match.
//
// This module only produces a "throw" descriptor; main.js owns the sim.

import { LANE } from "./physics.js";

export class InputController {
  constructor(canvas, opts) {
    this.canvas = canvas;
    this.onThrow = opts.onThrow;
    this.getEnabled = opts.getEnabled; // () => bool, true when ready to bowl
    this.onAimChange = opts.onAimChange; // (aimX, spin, power) => void

    this.aimX = 0; // ball start x (-halfWidth..halfWidth area near foul line)
    this.spin = 0; // -1..1
    this.power = 0; // 0..1 while charging
    this.charging = false;
    this.chargeStart = 0;
    this.maxChargeMs = 1100;

    this._bind();
    this._loop();
  }

  _bind() {
    const c = this.canvas;
    c.addEventListener("pointermove", (e) => this._move(e));
    c.addEventListener("pointerdown", (e) => this._down(e));
    window.addEventListener("pointerup", (e) => this._up(e));
    window.addEventListener("keydown", (e) => this._key(e, true));

    // Keep aim responsive even off-canvas drags.
    c.style.touchAction = "none";
  }

  _ndcX(e) {
    const r = this.canvas.getBoundingClientRect();
    const x = ((e.clientX - r.left) / r.width) * 2 - 1; // -1..1
    return x;
  }

  _move(e) {
    if (!this.getEnabled()) return;
    // Map horizontal mouse position to a start-x near the foul line.
    // Clamp inside the lane so you can still aim for the gutter intentionally.
    const ndc = this._ndcX(e);
    this.aimX = Math.max(-1, Math.min(1, ndc)) * (LANE.halfWidth - 0.05);
    this._emit();
  }

  _down(e) {
    if (!this.getEnabled()) return;
    this.charging = true;
    this.chargeStart = performance.now();
    this.power = 0;
  }

  _up() {
    if (!this.charging) return;
    this.charging = false;
    const held = performance.now() - this.chargeStart;
    const power = Math.max(0.18, Math.min(1, held / this.maxChargeMs));
    this.power = 0;
    this.onThrow({ aimX: this.aimX, spin: this.spin, power });
    this._emit();
  }

  _key(e, down) {
    if (e.key === "a" || e.key === "ArrowLeft") {
      this.spin = Math.max(-1, this.spin - 0.12);
      this._emit();
    } else if (e.key === "d" || e.key === "ArrowRight") {
      this.spin = Math.min(1, this.spin + 0.12);
      this._emit();
    }
  }

  setSpin(v) {
    this.spin = Math.max(-1, Math.min(1, v));
    this._emit();
  }

  _emit() {
    this.onAimChange?.(this.aimX, this.spin, this.power);
  }

  _loop() {
    const tick = () => {
      if (this.charging) {
        const held = performance.now() - this.chargeStart;
        this.power = Math.min(1, held / this.maxChargeMs);
        this._emit();
      }
      requestAnimationFrame(tick);
    };
    requestAnimationFrame(tick);
  }
}

// main.js — Game orchestration: scene, state machine, scoring, HUD.
import * as THREE from "three";
import {
  createGame,
  roll,
  totalScore,
  pinsStandingForCurrentBall,
  TOTAL_FRAMES,
} from "./scoring.js";
import {
  createPins,
  createBall,
  step,
  countFallen,
  isSettled,
  LANE,
  BALL_RADIUS,
} from "./physics.js";
import {
  createRenderer,
  createCamera,
  buildAlley,
  buildPins,
  buildBall,
  syncBall,
  syncPins,
} from "./scene.js";
import { InputController } from "./input.js";

const BALL_COLORS = [0x1565ff, 0xd11f5a, 0x18b562, 0xff8c1a, 0x9b51e0];

// ---- DOM ----
const canvas = document.getElementById("scene");
const loadingEl = document.getElementById("loading");
const scoreboardEl = document.getElementById("scoreboard");
const controlsEl = document.getElementById("controls");
const powerFill = document.getElementById("power-fill");
const spinSlider = document.getElementById("spin-slider");
const spinValue = document.getElementById("spin-value");
const statusEl = document.getElementById("status");
const messageEl = document.getElementById("message");
const newGameBtn = document.getElementById("new-game");

// ---- Three.js ----
const renderer = createRenderer(canvas);
const camera = createCamera();
const scene = new THREE.Scene();
buildAlley(scene);

// ---- Game state machine ----
const PHASE = {
  AIM: "aim",
  ROLLING: "rolling",
  SETTLING: "settling",
  BETWEEN: "between",
  GAMEOVER: "gameover",
};

let game,
  sim,
  ballMesh,
  pinMeshes,
  phase,
  ballColorIndex = 0;
let guideLine, aimX, spin;
let pinsBeforeRoll = 0; // pins standing at the start of the current ball
let settleTimer = 0;
let cameraTarget = new THREE.Vector3(0, 0.4, 8);

function freshPinMeshes(states) {
  if (pinMeshes) for (const m of pinMeshes) scene.remove(m);
  pinMeshes = buildPins(scene, states);
}

function freshBallMesh() {
  if (ballMesh) scene.remove(ballMesh);
  ballMesh = buildBall(scene, BALL_COLORS[ballColorIndex % BALL_COLORS.length]);
}

// Build the dashed aiming guide line (updated each aim frame).
function buildGuide() {
  if (guideLine) scene.remove(guideLine);
  const mat = new THREE.LineDashedMaterial({
    color: 0x35e0ff,
    dashSize: 0.18,
    gapSize: 0.12,
    transparent: true,
    opacity: 0.8,
  });
  const geo = new THREE.BufferGeometry();
  guideLine = new THREE.Line(geo, mat);
  scene.add(guideLine);
}

// Predict the rough path of the ball for the guide line, mirroring the hook.
function updateGuide() {
  if (!guideLine) return;
  const pts = [];
  let x = aimX;
  let z = 0;
  let vx = 0;
  const vz = 7.5;
  const steps = 60;
  for (let i = 0; i < steps; i++) {
    const t = i / steps;
    // Approximate hook: lateral drift increases down the lane.
    vx += spin * 0.9 * 0.016 * (0.4 + t);
    x += vx * 0.05;
    z += vz * 0.05;
    if (z > LANE.pinDeckZ + 0.5) break;
    if (Math.abs(x) > LANE.halfWidth) break;
    pts.push(new THREE.Vector3(x, 0.02, z));
  }
  guideLine.geometry.setFromPoints(pts);
  guideLine.computeLineDistances();
  guideLine.visible = phase === PHASE.AIM;
}

// Position the ball at the foul line ready to throw.
function placeBallAtFoul() {
  ballMesh.position.set(aimX, BALL_RADIUS, 0.1);
  ballMesh.quaternion.identity();
  ballMesh.visible = true;
}

function startGame() {
  game = createGame();
  ballColorIndex = 0;
  setupRack(true);
  phase = PHASE.AIM;
  aimX = 0;
  spin = 0;
  buildGuide();
  hide(messageEl);
  renderScoreboard();
  setStatus("Frame 1 — aim with the mouse, hold to charge, release to bowl.");
}

// (Re)build the pin rack. fullReset = brand new rack of 10.
function setupRack(fullReset) {
  let states = createPins();
  if (!fullReset) {
    // Keep only the pins still standing from the previous ball in this frame.
    states = createPins().filter((p) => standingIds.has(p.id));
  }
  sim = { ball: null, pins: states };
  freshPinMeshes(states);
  syncPins(pinMeshes, states);
}

let standingIds = new Set();

function beginRoll(throwData) {
  if (phase !== PHASE.AIM) return;
  aimX = throwData.aimX;
  spin = throwData.spin;

  pinsBeforeRoll = pinsStandingForCurrentBall(game);

  // Map power (0..1) -> ball speed (m/s). Min must still reach the pins.
  const speed = 5.0 + throwData.power * 5.5; // 5.0 .. 10.5 m/s
  // A small aim angle proportional to how far off-center you started, so
  // edge starts angle gently back toward the pocket (subtle, optional).
  const dirX = 0;
  const dirZ = 1;
  sim.ball = createBall({
    x: aimX,
    speed,
    dirX,
    dirZ,
    spin: spin * 0.22, // scale slider (-1..1) into physics spin range
  });

  phase = PHASE.ROLLING;
  guideLine.visible = false;
  setStatus("");
  hide(controlsEl);
}

function finishRoll() {
  const fallenNow = countFallen(sim.pins);
  // Pins knocked on THIS ball = standing-before minus standing-now.
  const standingNow = pinsBeforeRoll - fallenNow;
  const knocked = Math.max(0, Math.min(pinsBeforeRoll, fallenNow));

  // Record which physical pins remain standing (for partial rack rebuild).
  standingIds = new Set(
    sim.pins.filter((p) => !p.fallen && p.tilt < 0.7).map((p) => p.id),
  );

  const prevFrame = game.currentFrame;
  const result = roll(game, knocked);
  renderScoreboard();

  // Decide messaging.
  if (result.wasStrike) flash("STRIKE!", "#ffd54a");
  else if (result.wasSpare) flash("SPARE!", "#7fe0ff");
  else if (knocked === 0 && !sim.ball.inGutter) flash("Missed!", "#ff8a8a");
  else if (sim.ball.inGutter) flash("Gutter ball", "#ff8a8a");

  if (game.complete) {
    endGame();
    return;
  }

  // Set up the next ball.
  phase = PHASE.BETWEEN;
  settleTimer = 0;
  prepareNextBall(result, prevFrame);
}

function prepareNextBall(result, prevFrame) {
  const frameChanged = game.currentFrame !== prevFrame;
  // On a new frame, fresh rack + maybe a new ball color.
  if (frameChanged) {
    ballColorIndex++;
    setupRack(true);
  } else if (result.rackReset) {
    // 10th-frame strike/spare: fresh rack mid-frame.
    setupRack(true);
  } else {
    // Same frame, second ball: only the standing pins remain.
    setupRack(false);
  }
  freshBallMesh();
}

function endGame() {
  phase = PHASE.GAMEOVER;
  const total = totalScore(game);
  let title = "Game Over";
  let sub = `Final score: ${total}`;
  if (total === 300) {
    title = "PERFECT GAME!";
    sub = "300 — twelve strikes in a row.";
  } else if (total >= 200) {
    title = "Outstanding!";
  } else if (total >= 150) {
    title = "Great game!";
  }
  show(messageEl);
  messageEl.querySelector(".msg-title").textContent = title;
  messageEl.querySelector(".msg-sub").textContent = sub;
  hide(controlsEl);
}

// ---- HUD ----
function renderScoreboard() {
  const wrap = document.getElementById("sb-frames");
  wrap.innerHTML = "";
  for (let i = 0; i < TOTAL_FRAMES; i++) {
    const f = game.frames[i];
    const cell = document.createElement("div");
    cell.className = "sb-frame";
    if (i === game.currentFrame && !game.complete) cell.classList.add("active");

    const num = document.createElement("div");
    num.className = "sb-frame-num";
    num.textContent = i + 1;

    const rolls = document.createElement("div");
    rolls.className = "sb-rolls";
    rolls.innerHTML = renderRolls(f, i === TOTAL_FRAMES - 1);

    const cum = document.createElement("div");
    cum.className = "sb-cum";
    cum.textContent = f.cumulative !== null ? f.cumulative : "";

    cell.appendChild(num);
    cell.appendChild(rolls);
    cell.appendChild(cum);
    wrap.appendChild(cell);
  }
  document.getElementById("sb-total-value").textContent = totalScore(game);
}

function symbol(prev, val, isStrikeBall) {
  if (val === undefined || val === null) return "";
  if (isStrikeBall && val === 10) return "X";
  if (prev !== undefined && prev + val === 10 && prev !== 10) return "/";
  if (val === 0) return "-";
  return String(val);
}

function renderRolls(f, isTenth) {
  const r = f.rolls;
  const cells = [];
  if (!isTenth) {
    if (r[0] === 10) {
      cells.push("", "X");
    } else {
      cells.push(symbol(undefined, r[0], true));
      cells.push(symbol(r[0], r[1], false));
    }
  } else {
    // up to three balls; each strike shows X, spare second shows /
    let prevForSpare = undefined;
    for (let k = 0; k < 3; k++) {
      const v = r[k];
      if (v === undefined) {
        cells.push("");
        continue;
      }
      if (v === 10) {
        cells.push("X");
        prevForSpare = undefined; // strike resets spare context
      } else if (prevForSpare !== undefined && prevForSpare + v === 10) {
        cells.push("/");
        prevForSpare = undefined;
      } else {
        cells.push(v === 0 ? "-" : String(v));
        prevForSpare = v;
      }
    }
  }
  return cells
    .map((c) => `<span class="sb-roll">${c}</span>`)
    .join("");
}

function setStatus(t) {
  statusEl.textContent = t;
}

let flashTimeout;
function flash(text, color) {
  const el = document.getElementById("flash");
  el.textContent = text;
  el.style.color = color;
  el.classList.add("show");
  clearTimeout(flashTimeout);
  flashTimeout = setTimeout(() => el.classList.remove("show"), 1400);
}

function show(el) {
  el.classList.remove("hidden");
}
function hide(el) {
  el.classList.add("hidden");
}

// ---- Input wiring ----
const input = new InputController(canvas, {
  getEnabled: () => phase === PHASE.AIM,
  onThrow: (t) => beginRoll(t),
  onAimChange: (ax, sp, power) => {
    if (phase === PHASE.AIM) {
      aimX = ax;
      spin = sp;
      placeBallAtFoul();
      updateGuide();
    }
    powerFill.style.width = `${(power * 100).toFixed(0)}%`;
  },
});

spinSlider.addEventListener("input", () => {
  const v = parseFloat(spinSlider.value);
  input.setSpin(v);
  spin = v;
  spinValue.textContent =
    v === 0 ? "STRAIGHT" : v < 0 ? `HOOK L ${Math.abs(v).toFixed(1)}` : `HOOK R ${v.toFixed(1)}`;
  updateGuide();
});

newGameBtn.addEventListener("click", () => {
  show(controlsEl);
  startGame();
});

// ---- Main loop ----
let last = performance.now();
function animate(now) {
  const dt = Math.min(0.033, (now - last) / 1000);
  last = now;

  if (phase === PHASE.ROLLING && sim.ball) {
    // Sub-step the physics for stability at speed.
    const subs = 3;
    for (let i = 0; i < subs; i++) step(sim, dt / subs);
    syncBall(ballMesh, sim.ball, dt);
    syncPins(pinMeshes, sim.pins);

    // Camera follows the ball down the lane.
    const followZ = Math.min(sim.ball.z, LANE.pinDeckZ - 4);
    cameraTarget.set(sim.ball.x * 0.4, 0.6, sim.ball.z + 5);
    camera.position.x += (sim.ball.x * 0.3 - camera.position.x) * 0.05;
    camera.position.z += (followZ - 3 - camera.position.z) * 0.04;
    camera.lookAt(0, 0.5, Math.max(8, sim.ball.z + 4));

    if (!sim.ball.rolling && isSettled(sim)) {
      phase = PHASE.SETTLING;
      settleTimer = 0;
    }
  } else if (phase === PHASE.SETTLING) {
    // Let pins settle visually for a beat, then score.
    syncPins(pinMeshes, sim.pins);
    settleTimer += dt;
    step(sim, dt); // continue resolving any residual motion
    if (settleTimer > 0.7) {
      finishRoll();
    }
  } else if (phase === PHASE.BETWEEN) {
    settleTimer += dt;
    // Ease camera back to the bowling position.
    camera.position.x += (0 - camera.position.x) * 0.08;
    camera.position.z += (-2.6 - camera.position.z) * 0.08;
    camera.lookAt(0, 0.4, 8);
    if (settleTimer > 0.6) {
      phase = PHASE.AIM;
      placeBallAtFoul();
      buildGuide();
      updateGuide();
      show(controlsEl);
      const fn = game.currentFrame + 1;
      setStatus(`Frame ${fn} — aim and bowl.`);
    }
  } else if (phase === PHASE.AIM) {
    // idle: ensure camera at rest
    camera.position.x += (0 - camera.position.x) * 0.06;
    camera.position.z += (-2.6 - camera.position.z) * 0.06;
    camera.lookAt(0, 0.4, 8);
  }

  renderer.render(scene, camera);
  requestAnimationFrame(animate);
}

// ---- Resize ----
function onResize() {
  const w = window.innerWidth;
  const h = window.innerHeight;
  renderer.setSize(w, h, false);
  camera.aspect = w / h;
  camera.updateProjectionMatrix();
}
window.addEventListener("resize", onResize);

// ---- Boot ----
function boot() {
  onResize();
  freshBallMesh();
  startGame();
  placeBallAtFoul();
  buildGuide();
  updateGuide();
  hide(loadingEl);
  show(scoreboardEl);
  show(controlsEl);
  requestAnimationFrame(animate);
}

// Give the import map a tick, then boot.
boot();

