import { createGame, roll, totalScore, pinsStandingForCurrentBall } from "./scoring.js";
import { createPins, createBall, step, countFallen, isSettled } from "./physics.js";

// Simulate a full game the way main.js drives it: throw the ball, simulate,
// count knocked pins, feed to scoring, rebuild rack for ball 2 / next frame.
function simBall(standingIds, throwCfg){
  let pins = createPins();
  if (standingIds) pins = pins.filter(p => standingIds.has(p.id));
  const dz = 1;
  const ball = createBall({ x: throwCfg.x, speed: throwCfg.speed, dirX:0, dirZ:dz, spin: throwCfg.spin });
  const state = { ball, pins };
  for (let i=0;i<20000;i++){ step(state,1/180); if (isSettled(state) && !ball.rolling) break; }
  const knocked = countFallen(pins);
  const remaining = new Set(pins.filter(p=>!p.fallen && p.tilt<0.7).map(p=>p.id));
  return { knocked, remaining, gutter: ball.inGutter };
}

const game = createGame();
let standing = null; // null => fresh rack
let prevFrame = 0;
let ballsThrown = 0;
const rnd = (() => { let s=12345; return ()=> (s=(s*1103515245+12345)&0x7fffffff)/0x7fffffff; })();

while(!game.complete && ballsThrown < 40){
  const before = pinsStandingForCurrentBall(game);
  // random-ish throw config
  const cfg = { x: (rnd()-0.5)*0.4, speed: 6+rnd()*4, spin: (rnd()-0.5)*0.4 };
  const r = simBall(standing, cfg);
  const knocked = Math.max(0, Math.min(before, r.knocked));
  const prev = game.currentFrame;
  const res = roll(game, knocked);
  ballsThrown++;
  // rebuild rack like main.js
  if (game.currentFrame !== prev) { standing = null; }
  else if (res.rackReset) { standing = null; }
  else { standing = r.remaining; }
}

console.log("game complete:", game.complete);
console.log("balls thrown:", ballsThrown);
console.log("total:", totalScore(game));
// Validate every frame total is in 0..30 and cumulative monotonic.
let ok = true, lastCum = 0;
game.frames.forEach((f,i)=>{
  if (f.score !== null && (f.score < 0 || f.score > 30)) { ok=false; console.log("bad frame score", i, f.score); }
  if (f.cumulative !== null) { if (f.cumulative < lastCum) { ok=false; console.log("non-monotonic cum", i); } lastCum=f.cumulative; }
});
console.log("rolls per frame:", game.frames.map(f=>f.rolls.join(",")).join(" | "));
console.log("VALID:", ok && game.complete && totalScore(game) <= 300);
'

